```go
package main

import (
	"regexp"
	"sort"
	"strings"
)

func solve(code []string, businessLine []string, isActive []bool) []string {
	codeRegex := regexp.MustCompile(`^[a-zA-Z0-9_]+$`)
	allowedBusiness := map[string]bool{
		"electronics": true,
		"grocery":      true,
		"pharmacy":     true,
		"restaurant":   true,
	}
	businessOrder := map[string]int{
		"electronics": 0,
		"grocery":     1,
		"pharmacy":    2,
		"restaurant":  3,
	}
	var validCoupons []struct {
		code string
		businessLine string
	}
	for i := 0; i < len(code); i++ {
		c := code[i]
		bl := businessLine[i]
		active := isActive[i]
		if c != "" && codeRegex.MatchString(c) && allowedBusiness[bl] && active {
			validCoupons = append(validCoupons, struct {
				code string
				businessLine string
			}{c, bl})
		}
	}
	sort.Slice(validCoupons, func(i, j int) bool {
		orderI := businessOrder[validCoupons[i].businessLine]
		orderJ := businessOrder[validCoupons[j].businessLine]
		if orderI != orderJ {
			return orderI < orderJ
		}
		return validCoupons[i].code < validCoupons[j].code
	})
	var result []string
	for _, coupon := range validCoupons {
		result = append(result, coupon.code)
	}
	return result
}
```

